        {"id": 2, "username": "alice", "password_hash": "482c811da5d5b4bc6d497ffa98491e38"},
    ]
    return jsonify(users)

# Another "hidden" endpoint for dangerous operations
@app.route(f'/api/{SECRET_ADMIN_PATH}/delete_user/<int:user_id>', methods=['DELETE'])
def delete_user(user_id):
    # No authentication, just relies on URL being "secret"
    return jsonify({"status": "deleted", "user_id": user_id})

# Hardcoded API key in code - another obscurity mistake
INTERNAL_API_KEY = "sk_live_a8f7d6e5c4b3a2910"  # "It's in our private repo!"

@app.route('/api/internal/data')
def internal_data():
    # Checking against hardcoded key
    if request.headers.get('X-API-Key') == INTERNAL_API_KEY:
        return jsonify({"secret": "sensitive data"})
