**Attack Payload**:
```bash
# Attackers can discover hidden endpoints through:
# 1. JavaScript source code inspection
curl -s https://target.com/static/app.js | grep -oE '/api/[a-zA-Z0-9/]+'

# 2. Brute-force scanning with common wordlists
gobuster dir -u https://target.com/api/ -w /usr/share/wordlists/dirbuster/directory-list-2.3-medium.txt

# 3. Checking robots.txt, sitemap.xml
curl https://target.com/robots.txt

# 4. Browser developer tools - Network tab shows all API calls
# 5. Once found, exploit the unprotected endpoint:
curl https://target.com/api/x7k9m2p4q8w1/users
curl -X DELETE https://target.com/api/x7k9m2p4q8w1/delete_user/1
```

**Why This Is Dangerous**:
- Obscure URLs provide zero security against determined attackers
- Hardcoded secrets can be extracted from compiled code, git history, or memory dumps
- No authentication means anyone who discovers the URL has full access
- Violates the Kerckhoffs's principle: security should not depend on secrecy of the design

**SECURE VERSION**:

```python
from flask import Flask, request, jsonify, g
from functools import wraps
import jwt
import os
import logging
from datetime import datetime, timedelta

app = Flask(__name__)

# Configure logging for security events
logging.basicConfig(level=logging.INFO)
security_logger = logging.getLogger('security')

# SECURE: Load secrets from environment, never hardcode
app.config['SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY')
app.config['ADMIN_ROLES'] = ['admin', 'superadmin']

def require_auth(f):
    """Authentication decorator - verifies JWT token"""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization', '').replace('Bearer ', '')

        if not token:
            security_logger.warning(f"Missing auth token from {request.remote_addr}")
            return jsonify({"error": "Authentication required"}), 401

        try:
            payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            g.current_user = payload
        except jwt.ExpiredSignatureError:
            return jsonify({"error": "Token expired"}), 401
        except jwt.InvalidTokenError:
            security_logger.warning(f"Invalid token attempt from {request.remote_addr}")
            return jsonify({"error": "Invalid token"}), 401

        return f(*args, **kwargs)
    return decorated

def require_admin(f):
    """Authorization decorator - checks admin role"""
    @wraps(f)
    @require_auth
    def decorated(*args, **kwargs):
        user_role = g.current_user.get('role')

        if user_role not in app.config['ADMIN_ROLES']:
            security_logger.warning(
                f"Unauthorized admin access attempt by user {g.current_user.get('user_id')} "
                f"from {request.remote_addr}"
            )
            return jsonify({"error": "Admin access required"}), 403

        return f(*args, **kwargs)
    return decorated

# SECURE: Standard URL path with proper authentication and authorization
@app.route('/api/admin/users', methods=['GET'])
@require_admin
def get_all_users():
    """Admin endpoint - properly protected with auth + authz"""
    security_logger.info(
        f"Admin {g.current_user.get('user_id')} accessed user list from {request.remote_addr}"
    )
    # Never return password hashes, even to admins
    users = [
        {"id": 1, "username": "admin", "email": "admin@example.com"},
        {"id": 2, "username": "alice", "email": "alice@example.com"},
    ]
    return jsonify(users)

@app.route('/api/admin/users/<int:user_id>', methods=['DELETE'])
@require_admin
def delete_user(user_id):
    """Admin delete with audit logging"""
    security_logger.info(
        f"Admin {g.current_user.get('user_id')} deleted user {user_id} from {request.remote_addr}"
    )
    return jsonify({"status": "deleted", "user_id": user_id})

if __name__ == '__main__':
    if not app.config['SECRET_KEY']:
        raise ValueError("JWT_SECRET_KEY environment variable must be set")
    app.run()
```

**Key Security Controls**:
- **Authentication**: JWT tokens verify user identity before any access
- **Authorization**: Role-based access control ensures only admins can access admin endpoints
- **Audit Logging**: All admin actions are logged with user ID and IP address
- **Environment Variables**: Secrets loaded from environment, never hardcoded
- **Defense in Depth**: Multiple layers (auth + authz + logging) instead of single obscurity layer

No, this is a dangerous pattern called "security by obscurity" - relying on secret URLs or hidden endpoints instead of proper access controls. This was exactly how the Parler breach happened in 2021, where 70TB of user data was scraped because they relied on obscure URLs and sequential IDs.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const crypto = require('crypto');
const path = require('path');

const app = express();

// INSECURE: "Hidden" document URLs with no authentication
const documentStore = new Map();

// Generate "secret" URL when document uploaded
app.post('/api/documents/upload', (req, res) => {
  const docId = crypto.randomBytes(16).toString('hex');
  const secretPath = crypto.randomBytes(32).toString('hex');

  // Store document with "secret" path - NO AUTH CHECK
  documentStore.set(secretPath, {
    id: docId,
    filename: req.body.filename,
    content: req.body.content,
    uploadedAt: new Date()
  });

  // Return "unguessable" URL - this IS the only security
  res.json({
    documentUrl: `/docs/${secretPath}`,
    message: 'Share this secret link carefully!'
  });
});

// INSECURE: Anyone with the URL can access
app.get('/docs/:secretPath', (req, res) => {
  const doc = documentStore.get(req.params.secretPath);

  if (!doc) {
    return res.status(404).json({ error: 'Document not found' });
  }

  // No authentication, no authorization, no logging
  res.json(doc);
});

// INSECURE: Hidden admin endpoint - security by obscurity
app.get('/super-secret-admin-panel-xyz123', (req, res) => {
  const allDocs = Array.from(documentStore.values());
  res.json({ totalDocuments: allDocs.length, documents: allDocs });
});

app.listen(3000);
```

**Attack Vectors**:

```bash
# 1. URL leaked in referrer headers, browser history, logs
curl -H "Referer: https://victim.com/docs/abc123secret" https://attacker.com

# 2. Brute force "secret" paths (if short or predictable)
for i in $(seq 1 100000); do
  curl -s "https://victim.com/docs/$(printf '%032x' $i)" | grep -q 'content' && echo "Found: $i"
done

# 3. Directory enumeration finds hidden admin panel
gobuster dir -u https://victim.com -w /usr/share/wordlists/common.txt
# Discovers: /super-secret-admin-panel-xyz123
```

**Why This Is Dangerous**:
- URLs are logged in browser history, server logs, analytics, and referrer headers
- "Secret" URLs can be shared, leaked, or discovered through enumeration
- No revocation mechanism - once leaked, always accessible
- Hidden endpoints are easily discovered through fuzzing/scanning
- No audit trail of who accessed what
- Violates principle of defense in depth

**SECURE VERSION**:

```javascript
const express = require('express');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

const JWT_SECRET = process.env.JWT_SECRET;
const documentStore = new Map();
const documentPermissions = new Map();

// Rate limiting to prevent enumeration
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});
app.use(limiter);

// Authentication middleware
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.replace('Bearer ', '');

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    req.user = jwt.verify(token, JWT_SECRET);
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// Authorization check - proper access control
const authorizeDocument = (req, res, next) => {
  const docId = req.params.documentId;
  const userId = req.user.id;

  const permissions = documentPermissions.get(docId);

  if (!permissions || !permissions.includes(userId)) {
    // Log unauthorized access attempt
    console.log(`[SECURITY] Unauthorized access attempt: user=${userId}, doc=${docId}`);
    return res.status(403).json({ error: 'Access denied' });
  }

  next();
};

// Secure document upload with proper ownership
app.post('/api/documents', authenticate, (req, res) => {
  const docId = crypto.randomUUID();

  documentStore.set(docId, {
    id: docId,
    filename: req.body.filename,
    content: req.body.content,
    ownerId: req.user.id,
    uploadedAt: new Date()
  });

  // Set owner as having access
  documentPermissions.set(docId, [req.user.id]);

  console.log(`[AUDIT] Document created: id=${docId}, owner=${req.user.id}`);

  res.json({ documentId: docId });
});

// Secure document access with auth + authz
app.get('/api/documents/:documentId', authenticate, authorizeDocument, (req, res) => {
  const doc = documentStore.get(req.params.documentId);

  if (!doc) {
    return res.status(404).json({ error: 'Document not found' });
  }

  console.log(`[AUDIT] Document accessed: id=${doc.id}, user=${req.user.id}`);

  res.json(doc);
});

// Proper admin endpoint with role-based access
app.get('/api/admin/documents', authenticate, (req, res) => {
  if (req.user.role !== 'admin') {
    console.log(`[SECURITY] Admin access denied: user=${req.user.id}`);
    return res.status(403).json({ error: 'Admin access required' });
  }

  console.log(`[AUDIT] Admin accessed all documents: user=${req.user.id}`);
  const allDocs = Array.from(documentStore.values());
  res.json({ totalDocuments: allDocs.length, documents: allDocs });
});

app.listen(3000);
```

**Key Security Controls**:
- **Authentication**: JWT tokens verify user identity before any access
- **Authorization**: Explicit permission checks determine who can access each document
- **Audit Logging**: All access attempts (successful and failed) are logged
- **Rate Limiting**: Prevents brute-force enumeration attacks
- **Role-Based Access**: Admin functions require explicit admin role, not hidden URLs

Yes, shareable links can be secure when implemented with proper controls! The key difference from security by obscurity is adding time limits, access controls, and monitoring. Google Drive and Dropbox do this securely.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(express.json());
app.use(helmet());

const JWT_SECRET = process.env.JWT_SECRET;
const SHARE_LINK_SECRET = process.env.SHARE_LINK_SECRET;

// In production: use Redis or database
const documentStore = new Map();
const shareLinks = new Map();
const accessLogs = [];

// Aggressive rate limiting for share links
const shareLinkLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 10,
  message: { error: 'Too many access attempts' },
  standardHeaders: true,
  legacyHeaders: false
});

// Authentication middleware
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.replace('Bearer ', '');
  if (!token) return res.status(401).json({ error: 'Authentication required' });

  try {
    req.user = jwt.verify(token, JWT_SECRET);
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// Secure share link generation
app.post('/api/documents/:documentId/share', authenticate, (req, res) => {
  const docId = req.params.documentId;
  const doc = documentStore.get(docId);

  if (!doc || doc.ownerId !== req.user.id) {
    return res.status(403).json({ error: 'Access denied' });
  }

  // Generate cryptographically secure token
  const shareToken = crypto.randomBytes(32).toString('base64url');

  // Default 7 days, max 30 days
  const expiresInHours = Math.min(req.body.expiresInHours || 168, 720);
  const expiresAt = new Date(Date.now() + expiresInHours * 60 * 60 * 1000);

  const shareConfig = {
    token: shareToken,
    documentId: docId,
    createdBy: req.user.id,
    createdAt: new Date(),
    expiresAt: expiresAt,
    maxAccessCount: req.body.maxAccessCount || null, // Optional access limit
    accessCount: 0,
    allowedIPs: req.body.allowedIPs || null, // Optional IP restriction
    password: req.body.password ? hashPassword(req.body.password) : null,
    permissions: req.body.permissions || ['read'], // read, download
    isRevoked: false
  };

  shareLinks.set(shareToken, shareConfig);

  logAuditEvent('SHARE_LINK_CREATED', {
    documentId: docId,
    createdBy: req.user.id,
    expiresAt: expiresAt,
    hasPassword: !!shareConfig.password,
    hasIPRestriction: !!shareConfig.allowedIPs
  });

  res.json({
    shareUrl: `${process.env.BASE_URL}/shared/${shareToken}`,
    expiresAt: expiresAt,
    requiresPassword: !!shareConfig.password
  });
});

// Secure share link access
app.get('/shared/:shareToken', shareLinkLimiter, async (req, res) => {
  const { shareToken } = req.params;
  const clientIP = req.ip;
  const providedPassword = req.headers['x-share-password'];

  const shareConfig = shareLinks.get(shareToken);

  // Layer 1: Token existence check (constant-time)
  if (!shareConfig) {
    await simulateDelay(); // Prevent timing attacks
    logSecurityEvent('INVALID_SHARE_TOKEN', { token: shareToken.substring(0, 8), ip: clientIP });
    return res.status(404).json({ error: 'Link not found or expired' });
  }

  // Layer 2: Revocation check
  if (shareConfig.isRevoked) {
    logSecurityEvent('REVOKED_LINK_ACCESS', { documentId: shareConfig.documentId, ip: clientIP });
    return res.status(410).json({ error: 'This link has been revoked' });
  }

  // Layer 3: Expiration check
  if (new Date() > shareConfig.expiresAt) {
    logSecurityEvent('EXPIRED_LINK_ACCESS', { documentId: shareConfig.documentId, ip: clientIP });
    return res.status(410).json({ error: 'This link has expired' });
  }

  // Layer 4: Access count check
  if (shareConfig.maxAccessCount && shareConfig.accessCount >= shareConfig.maxAccessCount) {
    logSecurityEvent('MAX_ACCESS_EXCEEDED', { documentId: shareConfig.documentId, ip: clientIP });
    return res.status(410).json({ error: 'Maximum access limit reached' });
  }

  // Layer 5: IP restriction check
  if (shareConfig.allowedIPs && !shareConfig.allowedIPs.includes(clientIP)) {
    logSecurityEvent('IP_RESTRICTED_ACCESS', { documentId: shareConfig.documentId, ip: clientIP });
    return res.status(403).json({ error: 'Access denied from this location' });
  }

  // Layer 6: Password check
  if (shareConfig.password) {
    if (!providedPassword || !verifyPassword(providedPassword, shareConfig.password)) {
      logSecurityEvent('WRONG_SHARE_PASSWORD', { documentId: shareConfig.documentId, ip: clientIP });
      return res.status(401).json({ error: 'Password required', requiresPassword: true });
    }
  }

  // All checks passed - grant access
  const doc = documentStore.get(shareConfig.documentId);
  if (!doc) {
    return res.status(404).json({ error: 'Document no longer exists' });
  }

  // Increment access counter
  shareConfig.accessCount++;

  logAuditEvent('SHARED_DOCUMENT_ACCESSED', {
    documentId: shareConfig.documentId,
    ip: clientIP,
    accessCount: shareConfig.accessCount
  });

  // Return document with allowed permissions only
  const response = { filename: doc.filename };
  if (shareConfig.permissions.includes('read')) {
    response.content = doc.content;
  }

  res.json(response);
});

// Revoke share link
app.delete('/api/documents/:documentId/share/:shareToken', authenticate, (req, res) => {
  const { documentId, shareToken } = req.params;
  const shareConfig = shareLinks.get(shareToken);

  if (!shareConfig || shareConfig.documentId !== documentId) {
    return res.status(404).json({ error: 'Share link not found' });
  }

  const doc = documentStore.get(documentId);
  if (!doc || doc.ownerId !== req.user.id) {
    return res.status(403).json({ error: 'Access denied' });
  }

  // Soft revoke - keeps audit trail
  shareConfig.isRevoked = true;
  shareConfig.revokedAt = new Date();
  shareConfig.revokedBy = req.user.id;

  logAuditEvent('SHARE_LINK_REVOKED', {
    documentId: documentId,
    revokedBy: req.user.id
  });

  res.json({ message: 'Share link revoked' });
});

// List all active share links for a document
app.get('/api/documents/:documentId/shares', authenticate, (req, res) => {
  const { documentId } = req.params;
  const doc = documentStore.get(documentId);

  if (!doc || doc.ownerId !== req.user.id) {
    return res.status(403).json({ error: 'Access denied' });
  }

  const activeShares = Array.from(shareLinks.values())
    .filter(s => s.documentId === documentId && !s.isRevoked && new Date() < s.expiresAt)
    .map(s => ({
      token: s.token.substring(0, 8) + '...',
      createdAt: s.createdAt,
      expiresAt: s.expiresAt,
      accessCount: s.accessCount,
      maxAccessCount: s.maxAccessCount,
      hasPassword: !!s.password
    }));

  res.json({ shares: activeShares });
});

// Helper functions
function hashPassword(password) {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return `${salt}:${hash}`;
}

function verifyPassword(password, stored) {
  const [salt, hash] = stored.split(':');
  const verifyHash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
  return crypto.timingSafeEqual(Buffer.from(hash), Buffer.from(verifyHash));
}

async function simulateDelay() {
  return new Promise(resolve => setTimeout(resolve, 100 + Math.random() * 100));
}

function logAuditEvent(event, data) {
  accessLogs.push({ event, data, timestamp: new Date() });
  console.log(`[AUDIT] ${event}:`, JSON.stringify(data));
}

function logSecurityEvent(event, data) {
  accessLogs.push({ event, data, timestamp: new Date(), severity: 'warning' });
  console.log(`[SECURITY] ${event}:`, JSON.stringify(data));
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Cryptographic Token Generation**:
```javascript
// 32 bytes = 256 bits of entropy - infeasible to brute force
const shareToken = crypto.randomBytes(32).toString('base64url');
// Results in ~43 character URL-safe string
```

2. **Time-Limited Access**:
```javascript
// Links automatically expire
if (new Date() > shareConfig.expiresAt) {
  return res.status(410).json({ error: 'This link has expired' });
}
```

3. **Access Count Limits**:
```javascript
// One-time links or limited access
if (shareConfig.maxAccessCount && shareConfig.accessCount >= shareConfig.maxAccessCount) {
  return res.status(410).json({ error: 'Maximum access limit reached' });
}
```

**Additional Protections**:
- **IP Whitelisting**: Restrict access to specific networks for sensitive documents
- **Password Protection**: Additional authentication factor for high-value content
- **Instant Revocation**: Owner can immediately revoke any share link
- **Complete Audit Trail**: Every access attempt logged with IP, timestamp, outcome
- **Timing Attack Prevention**: Constant-time comparisons and artificial delays prevent token enumeration
- **Rate Limiting**: Aggressive limits on share link endpoints prevent brute-force
- **Referrer Policy**: Use `Referrer-Policy: no-referrer` header to prevent URL leakage

No, hiding admin endpoints behind obscure URLs is a classic security anti-pattern called "Security by Obscurity." This approach provides no real security because attackers routinely discover hidden endpoints through directory enumeration, JavaScript analysis, traffic interception, and reverse engineering.

**VULNERABLE CODE**:

```java
