**Why This Is Dangerous**:
- Hidden URLs are easily discovered through automated scanning (Burp Suite, DirBuster)
- Hardcoded secrets can be extracted from decompiled bytecode or memory dumps
- No authentication means anyone who discovers the URL has full admin access
- No audit logging means attacks go undetected
- Returning 404 instead of 403 is easily bypassed with timing analysis

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.io.*;
import java.util.logging.*;

@WebServlet("/admin/dashboard")
public class SecureAdminServlet extends HttpServlet {

    private static final Logger AUDIT_LOG = Logger.getLogger("SECURITY_AUDIT");
    private final AuthenticationService authService;
    private final AuthorizationService authzService;

    public SecureAdminServlet() {
        this.authService = new AuthenticationService();
        this.authzService = new AuthorizationService();
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String clientIp = request.getRemoteAddr();
        String sessionId = request.getSession().getId();

        // LAYER 1: Verify authentication via session/token
        User authenticatedUser = authService.getAuthenticatedUser(request);
        if (authenticatedUser == null) {
            AUDIT_LOG.warning(String.format(
                "Unauthenticated admin access attempt from IP: %s", clientIp));
            response.sendRedirect("/login?returnUrl=/admin/dashboard");
            return;
        }

        // LAYER 2: Verify authorization (role-based access control)
        if (!authzService.hasRole(authenticatedUser, "ADMIN")) {
            AUDIT_LOG.severe(String.format(
                "Unauthorized admin access by user %s from IP: %s",
                authenticatedUser.getUsername(), clientIp));
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access Denied");
            return;
        }

        // LAYER 3: Verify MFA for sensitive operations
        if (!authService.isMfaVerified(request.getSession())) {
            response.sendRedirect("/admin/mfa-challenge");
            return;
        }

        // LAYER 4: Log successful access
        AUDIT_LOG.info(String.format(
            "Admin dashboard accessed by %s from IP: %s, Session: %s",
            authenticatedUser.getUsername(), clientIp, sessionId));

        renderAdminDashboard(request, response, authenticatedUser);
    }

    private void renderAdminDashboard(HttpServletRequest request, 
            HttpServletResponse response, User user) throws IOException {
        response.setContentType("text/html");
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("X-Frame-Options", "DENY");
        response.setHeader("Cache-Control", "no-store, no-cache, must-revalidate");

        // Render dashboard with CSRF token for forms
        PrintWriter out = response.getWriter();
        String csrfToken = CsrfTokenManager.getToken(request.getSession());
        out.println("<h1>Admin Dashboard</h1>");
        out.println("<p>Welcome, " + escapeHtml(user.getDisplayName()) + "</p>");
        out.println("<input type='hidden' name='csrf_token' value='" + csrfToken + "'/>");
    }

    private String escapeHtml(String input) {
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;");
    }
}
```

**Key Security Controls**:
- **Proper Authentication**: Verifies user identity through secure session management, not hidden URLs
- **Role-Based Authorization**: Checks user has ADMIN role before granting access
- **Multi-Factor Authentication**: Requires MFA verification for sensitive admin operations
- **Audit Logging**: All access attempts (successful and failed) are logged with user, IP, and timestamp
- **Security Headers**: Prevents clickjacking, content sniffing, and caching of sensitive pages

API keys and internal service endpoints require even stronger protection than user-facing admin panels because they're prime targets for attackers. Obscure naming is never sufficient - you need cryptographic authentication, network segmentation, and comprehensive monitoring.

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import javax.crypto.*;
import javax.crypto.spec.*;
import java.security.*;
import java.time.*;
import java.util.*;
import java.util.logging.*;
import java.util.concurrent.*;

@WebServlet("/api/v1/internal/*")
public class SecureInternalApiServlet extends HttpServlet {

    private static final Logger AUDIT_LOG = Logger.getLogger("API_SECURITY_AUDIT");
    private static final Logger METRICS_LOG = Logger.getLogger("API_METRICS");

    // Rate limiting: 100 requests per minute per API key
    private final ConcurrentHashMap<String, RateLimiter> rateLimiters = new ConcurrentHashMap<>();
    private final ApiKeyValidator apiKeyValidator;
    private final ServiceAuthenticator serviceAuth;
    private final Set<String> allowedNetworks;

    public SecureInternalApiServlet() {
        this.apiKeyValidator = new ApiKeyValidator();
        this.serviceAuth = new ServiceAuthenticator();
        this.allowedNetworks = loadAllowedNetworks();
    }

    @Override
    protected void service(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        long startTime = System.currentTimeMillis();
        String requestId = UUID.randomUUID().toString();
        String clientIp = getClientIp(request);

        try {
            // LAYER 1: Network-level restriction (defense in depth)
            if (!isAllowedNetwork(clientIp)) {
                AUDIT_LOG.severe(String.format(
                    "[%s] Blocked request from unauthorized network: %s",
                    requestId, clientIp));
                response.sendError(HttpServletResponse.SC_FORBIDDEN);
                return;
            }

            // LAYER 2: API Key validation with HMAC verification
            String apiKey = extractApiKey(request);
            if (apiKey == null || !apiKeyValidator.isValid(apiKey)) {
                AUDIT_LOG.warning(String.format(
                    "[%s] Invalid or missing API key from IP: %s",
                    requestId, clientIp));
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
                return;
            }

            // LAYER 3: Request signature verification (prevents replay attacks)
            if (!verifyRequestSignature(request, apiKey)) {
                AUDIT_LOG.severe(String.format(
                    "[%s] Invalid request signature for key: %s from IP: %s",
                    requestId, maskApiKey(apiKey), clientIp));
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
                return;
            }

            // LAYER 4: Rate limiting per API key
            RateLimiter limiter = rateLimiters.computeIfAbsent(
                apiKey, k -> new RateLimiter(100, Duration.ofMinutes(1)));
            if (!limiter.tryAcquire()) {
                AUDIT_LOG.warning(String.format(
                    "[%s] Rate limit exceeded for key: %s",
                    requestId, maskApiKey(apiKey)));
                response.setHeader("Retry-After", "60");
                response.sendError(429, "Rate limit exceeded");
                return;
            }

            // LAYER 5: Service-to-service mutual TLS verification
            if (!serviceAuth.verifyMtls(request)) {
                AUDIT_LOG.severe(String.format(
                    "[%s] mTLS verification failed from IP: %s",
                    requestId, clientIp));
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
                return;
            }

            // All checks passed - process request
            AUDIT_LOG.info(String.format(
                "[%s] Authorized API request: method=%s, path=%s, key=%s, ip=%s",
                requestId, request.getMethod(), request.getPathInfo(),
                maskApiKey(apiKey), clientIp));

            super.service(request, response);

        } finally {
            // Log request metrics for monitoring
            long duration = System.currentTimeMillis() - startTime;
            METRICS_LOG.info(String.format(
                "request_id=%s duration_ms=%d status=%d",
                requestId, duration, response.getStatus()));
        }
    }

    private String extractApiKey(HttpServletRequest request) {
        // Check Authorization header first (preferred)
        String authHeader = request.getHeader("Authorization");
        if (authHeader != null && authHeader.startsWith("Bearer ")) {
            return authHeader.substring(7);
        }
        // Fallback to X-API-Key header
        return request.getHeader("X-API-Key");
    }

    private boolean verifyRequestSignature(HttpServletRequest request, String apiKey) {
        String timestamp = request.getHeader("X-Timestamp");
        String signature = request.getHeader("X-Signature");

        if (timestamp == null || signature == null) {
            return false;
        }

        // Prevent replay attacks: reject requests older than 5 minutes
        long requestTime = Long.parseLong(timestamp);
        long currentTime = System.currentTimeMillis();
        if (Math.abs(currentTime - requestTime) > 300000) {
            return false;
        }

        // Verify HMAC-SHA256 signature
        String payload = request.getMethod() + request.getRequestURI() + timestamp;
        String expectedSignature = computeHmacSignature(payload, getSecretForKey(apiKey));

        return MessageDigest.isEqual(
            signature.getBytes(), expectedSignature.getBytes());
    }

    private String computeHmacSignature(String payload, String secret) {
        try {
            Mac hmac = Mac.getInstance("HmacSHA256");
            SecretKeySpec keySpec = new SecretKeySpec(
                secret.getBytes(), "HmacSHA256");
            hmac.init(keySpec);
            byte[] hash = hmac.doFinal(payload.getBytes());
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            throw new SecurityException("Failed to compute HMAC", e);
        }
    }

    private String getSecretForKey(String apiKey) {
        // Retrieve from secure vault (HashiCorp Vault, AWS Secrets Manager, etc.)
        return SecretVaultClient.getSecret("api-key-secrets", apiKey);
    }

    private boolean isAllowedNetwork(String clientIp) {
        return allowedNetworks.stream()
            .anyMatch(network -> ipMatchesCidr(clientIp, network));
    }

    private Set<String> loadAllowedNetworks() {
        // Load from environment or secure configuration
        return Set.of(
            "10.0.0.0/8",      // Internal VPC
            "172.16.0.0/12",   // Kubernetes pod network
            "192.168.0.0/16"   // Private network
        );
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String maskApiKey(String apiKey) {
        if (apiKey == null || apiKey.length() < 8) {
            return "***";
        }
        return apiKey.substring(0, 4) + "..." + 
               apiKey.substring(apiKey.length() - 4);
    }

    private boolean ipMatchesCidr(String ip, String cidr) {
        // Implementation of CIDR matching
        return true; // Simplified for example
    }
}
