**Discovery Methods Attackers Use**:
```bash
# 1. Directory bruteforcing with common wordlists
gobuster dir -u http://target.com -w /usr/share/wordlists/admin-paths.txt

# 2. JavaScript source analysis reveals hidden endpoints
curl http://target.com/static/app.js | grep -E "admin|secret|hidden"

# 3. Browser developer tools show API calls
# Network tab reveals all HTTP requests including "hidden" ones

# 4. Wayback Machine historical analysis
curl "http://web.archive.org/cdx/search/cdx?url=target.com/*&output=json"

# 5. Robots.txt often reveals "hidden" paths
curl http://target.com/robots.txt
```

**Why This Is Dangerous**:
- URLs are logged in browser history, proxy logs, and server logs
- JavaScript bundles often contain all API endpoint URLs
- Automated scanners and fuzzers will discover obscure paths
- Former employees or contractors know the URLs
- HTTPS doesn't encrypt the URL path from all observers (SNI, logs)

**SECURE VERSION**:

```go
package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"strings"
	"time"

	"github.com/golang-jwt/jwt/v5"
)

type contextKey string

const userContextKey contextKey = "user"

var jwtSecret = []byte("your-256-bit-secret-from-env") // Load from environment

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	Role     string `json:"role"`
}

type Claims struct {
	UserID   int    `json:"user_id"`
	Username string `json:"username"`
	Role     string `json:"role"`
	jwt.RegisteredClaims
}

// SECURE: Proper authentication middleware
func authMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		authHeader := r.Header.Get("Authorization")
		if authHeader == "" {
			http.Error(w, "Authorization header required", http.StatusUnauthorized)
			return
		}

		tokenString := strings.TrimPrefix(authHeader, "Bearer ")
		if tokenString == authHeader {
			http.Error(w, "Invalid authorization format", http.StatusUnauthorized)
			return
		}

		claims := &Claims{}
		token, err := jwt.ParseWithClaims(tokenString, claims, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
				return nil, jwt.ErrSignatureInvalid
			}
			return jwtSecret, nil
		})

		if err != nil || !token.Valid {
			log.Printf("Invalid token attempt from %s", r.RemoteAddr)
			http.Error(w, "Invalid token", http.StatusUnauthorized)
			return
		}

		ctx := context.WithValue(r.Context(), userContextKey, claims)
		next.ServeHTTP(w, r.WithContext(ctx))
	}
}

// SECURE: Role-based authorization
func requireRole(role string, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		claims, ok := r.Context().Value(userContextKey).(*Claims)
		if !ok || claims.Role != role {
			log.Printf("Unauthorized access attempt by user %d to admin endpoint", claims.UserID)
			http.Error(w, "Forbidden", http.StatusForbidden)
			return
		}
		next.ServeHTTP(w, r)
	}
}

func adminUsersHandler(w http.ResponseWriter, r *http.Request) {
	claims := r.Context().Value(userContextKey).(*Claims)
	log.Printf("Admin %s accessed user list", claims.Username)

	users := []User{
		{ID: 1, Username: "admin", Email: "admin@company.com", Role: "admin"},
		{ID: 2, Username: "user1", Email: "user@company.com", Role: "user"},
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(users)
}

func main() {
	// SECURE: Clear endpoint naming with proper auth
	http.HandleFunc("/api/admin/users", authMiddleware(requireRole("admin", adminUsersHandler)))

	log.Println("Server starting on :8080")
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **Authentication**: JWT tokens verify user identity cryptographically
- **Authorization**: Role-based access control enforces permissions
- **Audit Logging**: All admin actions are logged with user context
- **Clear API Design**: Endpoints are clearly named - security comes from controls, not obscurity

Base64 encoding and hardcoded secrets are extremely dangerous examples of security by obscurity. Base64 is NOT encryption - it's trivially reversible, and hardcoded secrets get exposed through version control, binaries, and memory dumps.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/base64"
	"encoding/hex"
	"fmt"
	"io"
	"log"
	"os"
	"time"

	"github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/service/secretsmanager"
)

// VULNERABLE PATTERN - DO NOT USE
type InsecureConfig struct {
	// WRONG: Hardcoded secrets
	DBPassword string // = "SuperSecret123!"
	APIKey     string // = "sk-prod-abc123xyz"

	// WRONG: Base64 "obfuscation" - trivially reversible
	// echo "SuperSecret123!" | base64 => "U3VwZXJTZWNyZXQxMjMh"
	ObfuscatedPassword string // = "U3VwZXJTZWNyZXQxMjMh"
}

// =============================================================
// SECURE PRODUCTION IMPLEMENTATION
// =============================================================

// SecureConfig loads secrets from proper secret management
type SecureConfig struct {
	DBPassword      string
	APIKey          string
	EncryptionKey   []byte
	secretsClient   *secretsmanager.Client
	refreshInterval time.Duration
	lastRefresh     time.Time
}

// NewSecureConfig initializes configuration with proper secret management
func NewSecureConfig(ctx context.Context) (*SecureConfig, error) {
	// Load AWS configuration
	cfg, err := config.LoadDefaultConfig(ctx)
	if err != nil {
		return nil, fmt.Errorf("unable to load AWS config: %w", err)
	}

	client := secretsmanager.NewFromConfig(cfg)

	sc := &SecureConfig{
		secretsClient:   client,
		refreshInterval: 1 * time.Hour,
	}

	if err := sc.refreshSecrets(ctx); err != nil {
		return nil, err
	}

	return sc, nil
}

// refreshSecrets loads secrets from AWS Secrets Manager
func (sc *SecureConfig) refreshSecrets(ctx context.Context) error {
	// Load database password
	dbSecretName := os.Getenv("DB_SECRET_NAME")
	if dbSecretName == "" {
		return fmt.Errorf("DB_SECRET_NAME environment variable not set")
	}

	dbResult, err := sc.secretsClient.GetSecretValue(ctx, &secretsmanager.GetSecretValueInput{
		SecretId: &dbSecretName,
	})
	if err != nil {
		return fmt.Errorf("failed to retrieve DB secret: %w", err)
	}
	sc.DBPassword = *dbResult.SecretString

	// Load API key
	apiSecretName := os.Getenv("API_SECRET_NAME")
	if apiSecretName == "" {
		return fmt.Errorf("API_SECRET_NAME environment variable not set")
	}

	apiResult, err := sc.secretsClient.GetSecretValue(ctx, &secretsmanager.GetSecretValueInput{
		SecretId: &apiSecretName,
	})
	if err != nil {
		return fmt.Errorf("failed to retrieve API secret: %w", err)
	}
	sc.APIKey = *apiResult.SecretString

	// Load encryption key
	encKeyName := os.Getenv("ENCRYPTION_KEY_NAME")
	if encKeyName == "" {
		return fmt.Errorf("ENCRYPTION_KEY_NAME environment variable not set")
	}

	encResult, err := sc.secretsClient.GetSecretValue(ctx, &secretsmanager.GetSecretValueInput{
		SecretId: &encKeyName,
	})
	if err != nil {
		return fmt.Errorf("failed to retrieve encryption key: %w", err)
	}

	sc.EncryptionKey, err = hex.DecodeString(*encResult.SecretString)
	if err != nil {
		return fmt.Errorf("invalid encryption key format: %w", err)
	}

	sc.lastRefresh = time.Now()
	log.Println("Secrets refreshed successfully")
	return nil
}

// SecureDataHandler handles sensitive data with proper encryption
type SecureDataHandler struct {
	config *SecureConfig
}

// Encrypt uses AES-GCM for authenticated encryption
func (h *SecureDataHandler) Encrypt(plaintext []byte) (string, error) {
	block, err := aes.NewCipher(h.config.EncryptionKey)
	if err != nil {
		return "", fmt.Errorf("cipher creation failed: %w", err)
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return "", fmt.Errorf("GCM creation failed: %w", err)
	}

	nonce := make([]byte, aesGCM.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return "", fmt.Errorf("nonce generation failed: %w", err)
	}

	ciphertext := aesGCM.Seal(nonce, nonce, plaintext, nil)
	return base64.StdEncoding.EncodeToString(ciphertext), nil
}

// Decrypt decrypts AES-GCM encrypted data
func (h *SecureDataHandler) Decrypt(encryptedData string) ([]byte, error) {
	data, err := base64.StdEncoding.DecodeString(encryptedData)
	if err != nil {
		return nil, fmt.Errorf("base64 decode failed: %w", err)
	}

	block, err := aes.NewCipher(h.config.EncryptionKey)
	if err != nil {
		return nil, fmt.Errorf("cipher creation failed: %w", err)
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return nil, fmt.Errorf("GCM creation failed: %w", err)
	}

	nonceSize := aesGCM.NonceSize()
	if len(data) < nonceSize {
		return nil, fmt.Errorf("ciphertext too short")
	}

	nonce, ciphertext := data[:nonceSize], data[nonceSize:]
	plaintext, err := aesGCM.Open(nil, nonce, ciphertext, nil)
	if err != nil {
		return nil, fmt.Errorf("decryption failed: %w", err)
	}

	return plaintext, nil
}

// SecureLogger masks sensitive data in logs
type SecureLogger struct {
	logger *log.Logger
}

func NewSecureLogger() *SecureLogger {
	return &SecureLogger{
		logger: log.New(os.Stdout, "", log.LstdFlags),
	}
}

// LogSensitive logs with sensitive data properly masked
func (sl *SecureLogger) LogSensitive(message string, sensitiveFields map[string]string) {
	maskedFields := make(map[string]string)
	for key, value := range sensitiveFields {
		if len(value) > 4 {
			maskedFields[key] = value[:2] + "****" + value[len(value)-2:]
		} else {
			maskedFields[key] = "****"
		}
	}
	sl.logger.Printf("%s: %v", message, maskedFields)
}

