// Authentication middleware - validates JWT token
func requireAuth(next http.HandlerFunc) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		authHeader := r.Header.Get("Authorization")
		if authHeader == "" || !strings.HasPrefix(authHeader, "Bearer ") {
			http.Error(w, `{"error": "unauthorized"}`, http.StatusUnauthorized)
			return
		}

		tokenString := strings.TrimPrefix(authHeader, "Bearer ")
		claims := &Claims{}

		token, err := jwt.ParseWithClaims(tokenString, claims, func(token *jwt.Token) (interface{}, error) {
			return jwtSecret, nil
		})

		if err != nil || !token.Valid {
			log.Printf("Invalid token attempt from %s", r.RemoteAddr)
			http.Error(w, `{"error": "invalid token"}`, http.StatusUnauthorized)
			return
		}

		// Add user to context
		ctx := context.WithValue(r.Context(), userContextKey, claims)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// Authorization middleware - checks role
func requireRole(requiredRole string, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		claims, ok := r.Context().Value(userContextKey).(*Claims)
		if !ok {
			http.Error(w, `{"error": "unauthorized"}`, http.StatusUnauthorized)
			return
		}

		if !hasRole(claims.Role, requiredRole) {
			log.Printf("Access denied: user %s (role: %s) attempted to access %s requiring %s",
				claims.Username, claims.Role, r.URL.Path, requiredRole)
			http.Error(w, `{"error": "forbidden"}`, http.StatusForbidden)
			return
		}

		next.ServeHTTP(w, r)
	}
}

func hasRole(userRole, requiredRole string) bool {
	roleHierarchy := map[string]int{
		"user":       1,
		"admin":      2,
		"superadmin": 3,
	}
	return roleHierarchy[userRole] >= roleHierarchy[requiredRole]
}

func getEnvOrPanic(key string) string {
	// In production, load from secure config
	return "your-256-bit-secret-key-here"
}
