            g.current_user = payload
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token expired'}), 401
        except jwt.InvalidTokenError:
            audit_logger.warning(f"Invalid token attempt from {request.remote_addr}")
            return jsonify({'error': 'Invalid token'}), 401

        return f(*args, **kwargs)
    return decorated

def require_role(role):
    """Decorator requiring specific role"""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if g.current_user.get('role') != role:
                audit_logger.warning(
                    f"Unauthorized role access attempt: user={g.current_user.get('user_id')}, "
                    f"required={role}, actual={g.current_user.get('role')}"
                )
                return jsonify({'error': 'Insufficient permissions'}), 403
            return f(*args, **kwargs)
        return decorated
    return decorator

# SECURE: Public admin path with proper authentication
