    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
audit_logger = logging.getLogger('security.audit')
metrics_logger = logging.getLogger('security.metrics')

# Environment-based configuration
class Config:
    JWT_SECRET = os.environ['JWT_SECRET_KEY']
    SERVICE_SIGNING_KEY = os.environ['SERVICE_SIGNING_KEY']
    ENCRYPTION_KEY = os.environ['ENCRYPTION_KEY']
    REDIS_URL = os.environ['REDIS_URL']
    SERVICE_NAME = os.environ.get('SERVICE_NAME', 'unknown')
    ENVIRONMENT = os.environ.get('ENVIRONMENT', 'development')

    # Service-to-service trust configuration
    ALLOWED_SERVICES = {
        'user-service': {'scopes': ['users:read', 'users:write']},
        'payment-service': {'scopes': ['payments:process', 'users:read']},
        'notification-service': {'scopes': ['users:read', 'notifications:send']}
    }

config = Config()
redis_client = redis.from_url(config.REDIS_URL)
fernet = Fernet(config.ENCRYPTION_KEY.encode())

class ServiceAuthenticator:
    """Mutual TLS alternative: HMAC-based service authentication"""

    @staticmethod
    def generate_service_token(service_name: str, scopes: list) -> str:
        """Generate signed service-to-service token"""
        payload = {
            'service': service_name,
            'scopes': scopes,
            'timestamp': int(time.time()),
            'nonce': os.urandom(16).hex(),
            'exp': int(time.time()) + 300  # 5 minute expiry
        }

        # Sign the payload
        message = json.dumps(payload, sort_keys=True)
        signature = hmac.new(
            config.SERVICE_SIGNING_KEY.encode(),
            message.encode(),
            hashlib.sha256
        ).hexdigest()

        return jwt.encode(
            {**payload, 'sig': signature},
            config.JWT_SECRET,
            algorithm='HS256'
        )

    @staticmethod
    def verify_service_token(token: str) -> dict:
        """Verify service token with replay attack prevention"""
        try:
            payload = jwt.decode(token, config.JWT_SECRET, algorithms=['HS256'])

            # Check expiration
            if payload['exp'] < int(time.time()):
                raise ValueError("Token expired")

            # Prevent replay attacks using nonce
            nonce_key = f"service_nonce:{payload['nonce']}"
            if redis_client.exists(nonce_key):
                raise ValueError("Replay attack detected")

            # Store nonce with TTL matching token expiry
            redis_client.setex(nonce_key, 600, '1')  # 10 min TTL

            # Verify HMAC signature
            sig = payload.pop('sig')
            message = json.dumps(payload, sort_keys=True)
            expected_sig = hmac.new(
                config.SERVICE_SIGNING_KEY.encode(),
                message.encode(),
                hashlib.sha256
            ).hexdigest()

            if not hmac.compare_digest(sig, expected_sig):
                raise ValueError("Invalid signature")

            # Verify service is known and scopes are valid
            service_config = config.ALLOWED_SERVICES.get(payload['service'])
            if not service_config:
                raise ValueError(f"Unknown service: {payload['service']}")

            # Verify requested scopes are allowed
            for scope in payload['scopes']:
                if scope not in service_config['scopes']:
                    raise ValueError(f"Invalid scope: {scope}")

            return payload

        except jwt.InvalidTokenError as e:
            raise ValueError(f"Invalid token: {e}")

def require_service_auth(required_scope: str):
    """Decorator for service-to-service authentication"""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            token = request.headers.get('X-Service-Token')

            if not token:
                audit_logger.warning(
                    f"Missing service token from {request.remote_addr}",
                    extra={'event': 'service_auth_failure'}
                )
                return jsonify({'error': 'Service authentication required'}), 401

            try:
                service_info = ServiceAuthenticator.verify_service_token(token)

                # Check required scope
                if required_scope not in service_info['scopes']:
                    audit_logger.warning(
                        f"Scope denied: service={service_info['service']}, "
                        f"required={required_scope}, granted={service_info['scopes']}"
                    )
                    return jsonify({'error': 'Insufficient scope'}), 403

                g.calling_service = service_info

                audit_logger.info(
                    f"Service auth success: {service_info['service']} -> {required_scope}",
                    extra={'event': 'service_auth_success'}
                )

            except ValueError as e:
                audit_logger.warning(
                    f"Service auth failed: {e} from {request.remote_addr}",
                    extra={'event': 'service_auth_failure'}
                )
                return jsonify({'error': 'Invalid service credentials'}), 401

            return f(*args, **kwargs)
        return decorated
    return decorator

def rate_limit_service(max_requests: int, window_seconds: int):
    """Rate limiting for service-to-service calls"""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            service = g.calling_service['service']
            key = f"rate_limit:{service}:{f.__name__}"

            current = redis_client.incr(key)
            if current == 1:
                redis_client.expire(key, window_seconds)

            if current > max_requests:
                metrics_logger.warning(
                    f"Rate limit exceeded: {service} on {f.__name__}",
                    extra={'event': 'rate_limit_exceeded'}
                )
                return jsonify({'error': 'Rate limit exceeded'}), 429

            return f(*args, **kwargs)
        return decorated
    return decorator

