**Key Security Controls**:
- **Authentication Required**: Every sensitive endpoint verifies JWT tokens before processing
- **Role-Based Authorization**: Admin functions require specific roles, not just authentication
- **Rate Limiting**: Prevents brute-force discovery and abuse
- **Audit Logging**: All access attempts are logged for forensic analysis
- **Environment Separation**: Debug endpoints completely disabled in production

Random URLs are **marginally better** than predictable paths but still fundamentally flawed as a security control. The Parler breach demonstrated this perfectly - their "unpredictable" URLs were still discoverable through JavaScript inspection. Random paths provide **obfuscation, not security**.

**Why Random URLs Fail**:
1. Client-side code must know the URL - it's in your JavaScript bundle
2. Browser history, logs, and referrer headers leak the URLs
3. One compromised user/insider reveals all "secret" paths
4. Proxy logs, CDN logs, and monitoring tools capture these URLs

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const { createLogger, transports, format } = require('winston');
const redis = require('redis');

const app = express();

// Security headers
app.use(helmet());
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ["'self'"],
    scriptSrc: ["'self'"],
    styleSrc: ["'self'"],
    imgSrc: ["'self'"],
    connectSrc: ["'self'"],
    frameSrc: ["'none'"]
  }
}));

// Structured audit logging
const auditLogger = createLogger({
  format: format.combine(
    format.timestamp(),
    format.json()
  ),
  transports: [
    new transports.File({ filename: 'audit.log' }),
    new transports.Console()
  ]
});

// Redis for session management and rate limiting
const redisClient = redis.createClient({
  url: process.env.REDIS_URL
});

// Multi-layer authentication middleware
const secureAuthentication = async (req, res, next) => {
  const requestId = crypto.randomUUID();
  req.requestId = requestId;

  try {
    // Layer 1: Token presence
    const authHeader = req.headers['authorization'];
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      auditLogger.warn({
        event: 'AUTH_MISSING',
        requestId,
        ip: req.ip,
        path: req.path,
        userAgent: req.headers['user-agent']
      });
      return res.status(401).json({ error: 'Authentication required' });
    }

    const token = authHeader.split(' ')[1];

    // Layer 2: Token validation
    const decoded = jwt.verify(token, process.env.JWT_SECRET, {
      algorithms: ['HS256'],
      issuer: 'myapp',
      audience: 'myapp-api'
    });

    // Layer 3: Token revocation check (prevents use of stolen tokens)
    const isRevoked = await redisClient.get(`revoked:${token}`);
    if (isRevoked) {
      auditLogger.warn({
        event: 'REVOKED_TOKEN_USED',
        requestId,
        userId: decoded.sub,
        ip: req.ip
      });
      return res.status(401).json({ error: 'Token revoked' });
    }

    // Layer 4: User status verification
    const user = await getUserById(decoded.sub);
    if (!user || user.status !== 'active') {
      auditLogger.warn({
        event: 'INACTIVE_USER_ACCESS',
        requestId,
        userId: decoded.sub,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Account inactive' });
    }

    req.user = user;
    next();
  } catch (err) {
    auditLogger.error({
      event: 'AUTH_ERROR',
      requestId,
      error: err.message,
      ip: req.ip
    });
    return res.status(401).json({ error: 'Invalid authentication' });
  }
};

// Granular permission checking
const checkPermission = (requiredPermission) => {
  return async (req, res, next) => {
    const userPermissions = await getUserPermissions(req.user.id);

    if (!userPermissions.includes(requiredPermission)) {
      auditLogger.warn({
        event: 'PERMISSION_DENIED',
        requestId: req.requestId,
        userId: req.user.id,
        required: requiredPermission,
        had: userPermissions,
        path: req.path
      });
      return res.status(403).json({ error: 'Permission denied' });
    }

    next();
  };
};

// IP-based access control for admin functions
const adminNetworkCheck = (req, res, next) => {
  const allowedNetworks = process.env.ADMIN_ALLOWED_IPS?.split(',') || [];
  const clientIP = req.ip;

  // In production, admin functions may require VPN/internal network
  if (process.env.NODE_ENV === 'production' && allowedNetworks.length > 0) {
    const isAllowed = allowedNetworks.some(network => 
      clientIP.startsWith(network.trim())
    );

    if (!isAllowed) {
      auditLogger.warn({
        event: 'ADMIN_NETWORK_VIOLATION',
        requestId: req.requestId,
        ip: clientIP,
        userId: req.user?.id
      });
      return res.status(403).json({ error: 'Access denied from this network' });
    }
  }
  next();
};

// Strict rate limiting for admin endpoints
const adminRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 50,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    auditLogger.warn({
      event: 'RATE_LIMIT_EXCEEDED',
      requestId: req.requestId,
      ip: req.ip,
      userId: req.user?.id,
      path: req.path
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});

// SECURE ADMIN ROUTES - Defense in depth, not obscurity
const adminRouter = express.Router();

// All admin routes require multiple security layers
adminRouter.use(adminRateLimiter);
adminRouter.use(secureAuthentication);
adminRouter.use(adminNetworkCheck);

adminRouter.get('/users',
  checkPermission('users:read'),
  async (req, res) => {
    auditLogger.info({
      event: 'ADMIN_USERS_LIST',
      requestId: req.requestId,
      userId: req.user.id,
      ip: req.ip
    });

    // Return only necessary, non-sensitive fields
    const users = await db.query(
      'SELECT id, email, created_at, last_login FROM users LIMIT 100'
    );
    res.json({ users, requestId: req.requestId });
  }
);

adminRouter.delete('/users/:id',
  checkPermission('users:delete'),
  async (req, res) => {
    const targetUserId = parseInt(req.params.id, 10);

    // Prevent self-deletion
    if (targetUserId === req.user.id) {
      return res.status(400).json({ error: 'Cannot delete own account' });
    }

    auditLogger.info({
      event: 'ADMIN_USER_DELETE',
      requestId: req.requestId,
      adminId: req.user.id,
      targetUserId,
      ip: req.ip
    });

    await db.query('UPDATE users SET status = $1 WHERE id = $2', ['deleted', targetUserId]);
    res.json({ success: true, requestId: req.requestId });
  }
);

// Mount admin routes - path is public, security is in the middleware
app.use('/api/admin', adminRouter);

// Health check for monitoring - no sensitive data
app.get('/api/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});
